#!/usr/bin/env python3
"""
plan.py — Generate an execution plan for a complex task.

Reads the repo structure and docs/ARCHITECTURE.md, then uses an LLM
to generate a pre-filled EXECUTION_PLAN_TEMPLATE.md for the given task.
"""
import argparse
import os
import sys
from pathlib import Path


TEMPLATE = """# Execution Plan: {task}

## Status: Planning
## Complexity: {complexity}
## Packages affected: {packages}

## Goal

{goal}

## Steps

{steps}

## Decisions

| Decision | Rationale | Date |
|----------|-----------|------|
| | | |

## Known risks

- {risk}

---

*Generated by harness/scripts/plan.py. Review and fill in before starting.*
"""


def detect_affected_packages(task: str, info: dict) -> list[str]:
    """Heuristic: find packages mentioned in the task description."""
    task_lower = task.lower()
    affected = []
    for pkg in info.get("packages", []):
        pkg_clean = pkg.replace("-", " ").replace("_", " ")
        if pkg_clean in task_lower or pkg in task_lower:
            affected.append(pkg)
    return affected or ["(review docs/ARCHITECTURE.md to identify)"]


def estimate_complexity(task: str, affected: list[str]) -> str:
    if len(affected) > 3 or any(
        kw in task.lower()
        for kw in ["migration", "cross-chain", "consensus", "security", "ibc", "governance"]
    ):
        return "High"
    if len(affected) > 1 or any(
        kw in task.lower()
        for kw in ["refactor", "interface", "breaking change", "new pallet", "new package"]
    ):
        return "Medium"
    return "Low"


def generate_steps(lang: str, complexity: str) -> str:
    base = [
        "- [ ] Step 1: Read docs/ARCHITECTURE.md for relevant dependency rules",
        "- [ ] Step 2: Create/update execution plan (this file)",
        "- [ ] Step 3: [describe first implementation step]",
        "- [ ] Step 4: [describe next implementation step]",
        "- [ ] Step 5: Write tests covering happy path + all error variants",
    ]
    if lang == "rust":
        base += [
            "- [ ] Step 6: Add/update benchmarks if new extrinsics added",
            "- [ ] Step 7: Run `cargo test --workspace` — must pass",
            "- [ ] Step 8: Run `bash scripts/agent-lint.sh` — must pass",
            "- [ ] Step 9: Run `cargo clippy --workspace -- -D warnings` — must pass",
        ]
    elif lang == "go":
        base += [
            "- [ ] Step 6: Run `go test ./... -count=1` — must pass",
            "- [ ] Step 7: Run `go test -race ./...` — must pass",
            "- [ ] Step 8: Run `bash scripts/agent-lint.sh` — must pass",
            "- [ ] Step 9: Check coverage ≥ 90%",
        ]
    else:
        base += [
            "- [ ] Step 6: Run tests — must pass",
            "- [ ] Step 7: Run `bash scripts/agent-lint.sh` — must pass",
        ]
    if complexity == "High":
        base += [
            "- [ ] Step 10: Update docs/ARCHITECTURE.md if structure changed",
            "- [ ] Step 11: Get architecture review before merging",
        ]
    base.append("- [ ] Step N: Open PR with this plan linked in description")
    return "\n".join(base)


def main():
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--task", required=True, help="Task description")
    parser.add_argument("--repo", required=True, help="Path to repository root")
    parser.add_argument("--output", help="Output file (default: docs/plans/<slug>.md)")
    parser.add_argument("--dry-run", action="store_true", help="Print plan without writing")
    args = parser.parse_args()

    repo = Path(args.repo).resolve()

    # Minimal repo inspection
    lang = "unknown"
    if (repo / "Cargo.toml").exists():
        lang = "rust"
    elif (repo / "go.mod").exists():
        lang = "go"

    packages = []
    if lang == "rust" and (repo / "pallets").exists():
        packages = [p.name for p in (repo / "pallets").iterdir() if p.is_dir()]
    elif lang == "go" and (repo / "internal").exists():
        packages = [p.name for p in (repo / "internal").iterdir() if p.is_dir()]

    info = {"language": lang, "packages": packages}
    affected = detect_affected_packages(args.task, info)
    complexity = estimate_complexity(args.task, affected)
    steps = generate_steps(lang, complexity)

    plan = TEMPLATE.format(
        task=args.task,
        complexity=complexity,
        packages=", ".join(affected),
        goal=f"[Describe what done looks like for: {args.task}]",
        steps=steps,
        risk="[Identify any architectural risks or blockers]",
    )

    # Determine output path
    if args.output:
        out = Path(args.output)
    else:
        slug = args.task.lower()
        slug = "".join(c if c.isalnum() else "-" for c in slug)
        slug = slug[:60].strip("-")
        out = repo / "docs" / "plans" / f"{slug}.md"

    if args.dry_run:
        print(plan)
    else:
        out.parent.mkdir(parents=True, exist_ok=True)
        out.write_text(plan)
        print(f"Execution plan written to: {out}")
        print(f"  Complexity: {complexity}")
        print(f"  Packages:   {', '.join(affected)}")


if __name__ == "__main__":
    main()
